%[text] ## Import data 
% Set up the Import Options and import the data %[task:6ec8]
opts = spreadsheetImportOptions("NumVariables", 12);

% Specify sheet and range
opts.Sheet = "Sheet1";
opts.DataRange = "A2:L243797";

% Specify column names and types
opts.VariableNames = ["Time", "state", "event_type", "damage_property", "damage_crops", "begin_lat", "begin_lon", "end_lat", "end_lon", "event_narrative", "storm_duration", "weathercats"];
opts.VariableTypes = ["datetime", "categorical", "categorical", "categorical", "categorical", "string", "string", "string", "string", "string", "categorical", "categorical"];

% Specify variable properties
opts = setvaropts(opts, ["begin_lat", "begin_lon", "end_lat", "end_lon", "event_narrative"], "WhitespaceRule", "preserve");
opts = setvaropts(opts, ["state", "event_type", "damage_property", "damage_crops", "begin_lat", "begin_lon", "end_lat", "end_lon", "event_narrative", "storm_duration", "weathercats"], "EmptyFieldRule", "auto");

% Import the data
weatherData = readtable("C:\Users\Filip\Documents\Praca\Inne materiały\MATLAB Expo 2025\MATLAB_Expo\MATLAB_LTC\weatherData.xlsx", opts, "UseExcel", false);

% Clear temporary variables
clear opts

% Display results
weatherData %[task:6ec8] %[output:23ed1161]
%%
%[text] ## Preprocess data
% Define variable names for damage properties and crops
vars1 = ["damage_property", "damage_crops"];
for i = 1:length(vars1)
    vname = vars1(i);
    % Convert the weather data field to string format
    weatherData.(vname) = string(weatherData.(vname));
    % Identify entries containing "M" for million
    idxM = contains(weatherData.(vname),"M");
    % Remove "K" and "M" from the data
    weatherData.(vname) = erase(weatherData.(vname),["K","M"]);
    % Convert the cleaned data to double
    weatherData.(vname) = double(weatherData.(vname));
    % Scale entries that were originally in millions
    weatherData.(vname)(idxM) = weatherData.(vname)(idxM).*1e3;
end

% Define variable names for longitude and latitude
vars2 = ["begin_lon", "begin_lat"];
for i = 1:length(vars2)
    vname = vars2(i);
    % Convert the weather data field to double format
    weatherData.(vname) = double(weatherData.(vname));
end

%%
% Calculate the total damage by summing the vars1 columns and storing in a new column
weatherData.damage_total = sum(weatherData{:, vars1}, 2, 'omitnan');

% Set damage_total to NaN where both damage_crops and damage_property are missing using ismissing
missingIdx = ismissing(weatherData.damage_crops) & ismissing(weatherData.damage_property);
weatherData.damage_total(missingIdx) = NaN;

% Set the units for damage properties and total damage
weatherData.Properties.VariableUnits{'damage_property'} = '$K';
weatherData.Properties.VariableUnits{'damage_crops'} = '$K';
weatherData.Properties.VariableUnits{'damage_total'} = '$K';

%%

% Remove missing data %[task:1bd4]
[weatherData_CMD,missingIndices] = rmmissing(weatherData);

% Display results
figure %[output:40f4bd08]
% Get locations of missing data
indicesForPlot = ismissing(weatherData.Time);
mask = missingIndices & ~indicesForPlot;

% Plot cleaned data
plot(find(~missingIndices),weatherData_CMD.Time,SeriesIndex=1,LineWidth=1.5, ... %[output:40f4bd08]
    DisplayName="Cleaned data") %[output:40f4bd08]
hold on %[output:40f4bd08]

% Plot data in rows where other variables contain missing entries
plot(find(mask),weatherData.Time(mask),"x",SeriesIndex="none", ... %[output:40f4bd08]
    DisplayName="Removed by other variables") %[output:40f4bd08]

% Plot removed missing entries
x = repelem(find(indicesForPlot),3);
y = repmat([ylim(gca) missing]',nnz(indicesForPlot),1);
plot(x,y,"Color",[145 145 145]/255,DisplayName="Removed missing entries")
title("Number of removed missing entries: " + nnz(indicesForPlot)) %[output:40f4bd08]

hold off %[output:40f4bd08]
legend %[output:40f4bd08]
ylabel("Time") %[output:40f4bd08]
clear indicesForPlot mask x y %[task:1bd4]
% Fill outliers %[task:731d]
[newTable,outlierIndices,lo,hi] = filloutliers(weatherData_CMD,"linear", ...
    "movmedian",2, ...
    DataVariables=["damage_property","damage_crops","begin_lat","begin_lon", ...
    "damage_total"]);

% Display results
figure %[output:999d3009]
plot(weatherData_CMD.damage_total,SeriesIndex=6,DisplayName="Input data") %[output:999d3009]
hold on %[output:999d3009]
plot(newTable.damage_total,SeriesIndex=1,LineWidth=1.5, ... %[output:999d3009]
    DisplayName="Cleaned data") %[output:999d3009]

% Plot outliers
plot(find(outlierIndices(:,13)),weatherData_CMD.damage_total(outlierIndices(:,13)), ...
    "x",Color=[145 145 145]/255,DisplayName="Outliers")

% Plot filled outliers
plot(find(outlierIndices(:,13)),newTable.damage_total(outlierIndices(:,13)),".", ...
    MarkerSize=12,SeriesIndex=2,DisplayName="Filled outliers")

% Plot outlier thresholds
plot([(1:numel(weatherData_CMD.damage_total))'; missing; (1:numel(weatherData_CMD.damage_total))'], ... %[output:999d3009]
    [hi.damage_total(:); missing; lo.damage_total(:)],Color=[145 145 145]/255, ... %[output:999d3009]
    DisplayName="Outlier thresholds") %[output:999d3009]

hold off %[output:999d3009]
title("Number of outliers cleaned: " + nnz(outlierIndices(:,13))) %[output:999d3009]
legend %[output:999d3009]
ylabel("damage_total",Interpreter="none") %[output:999d3009]
clear lo hi %[task:731d]
%%
% Extract rows from newTable with the 100 largest values of column damage_total
topDamageRows = newTable(ismember(newTable.damage_total, ...
    maxk(newTable.damage_total, 100)), :);
% Create geobubble of selected data %[task:612a]
gb = geobubble(topDamageRows.begin_lat,topDamageRows.begin_lon,topDamageRows.damage_total); %[output:36ed7483]

% Add title
title("topDamageRows.begin_lat vs. topDamageRows.begin_lon") %[task:612a] %[output:36ed7483]


